 *
 * Only trust proxies you control — X-Forwarded-For is client-spoofable when the
 * upstream hop is untrusted, letting attackers evade the limiter or poison other
 * clients' buckets. For per-user/API-key limits, pass a custom `keyGenerator`.
 * ---------------------------------------------------------------------------
 */

/**
 * @param {Object}   [options]
 * @param {number}   [options.windowMs=60000]          Window size in ms.
 * @param {number}   [options.maxRequests=100]         Max requests per window.
 * @param {number}   [options.cleanupIntervalMs=60000] Background sweep cadence.
 * @param {Function} [options.keyGenerator]            (req) => string. Default: req.ip.
 * @returns {Function} Express middleware, with a `.close()` method attached.
 */
function createRateLimiter(options = {}) {
  const {
    windowMs = 60000,
    maxRequests = 100,
    cleanupIntervalMs = 60000,
    keyGenerator = (req) => req.ip,
  } = options;

  if (!Number.isFinite(windowMs) || windowMs <= 0) {
    throw new TypeError('windowMs must be a positive number');
  }
  if (!Number.isInteger(maxRequests) || maxRequests <= 0) {
    throw new TypeError('maxRequests must be a positive integer');
  }

  // Map<clientKey, number[]> — each value is an ascending-sorted array of
  // request timestamps (ms). Timestamps are appended in arrival order, which is
  // monotonic, so the array stays sorted without explicit sorting.
  const hits = new Map();

  // Drop every front timestamp older than the window. Array is sorted ascending,
  // so we just find the first index still inside the window and splice the rest.
  function evictExpired(timestamps, windowStart) {
    let firstValid = 0;
    while (firstValid < timestamps.length && timestamps[firstValid] <= windowStart) {
      firstValid++;
    }
    if (firstValid > 0) {
      timestamps.splice(0, firstValid);
    }
  }

  const middleware = function rateLimiter(req, res, next) {
    const now = Date.now();
    const windowStart = now - windowMs;
    const key = keyGenerator(req);

    let timestamps = hits.get(key);
    if (!timestamps) {
      timestamps = [];
      hits.set(key, timestamps);
    }

    // Slide the window: drop everything that has aged out.
    evictExpired(timestamps, windowStart);

    if (timestamps.length >= maxRequests) {
      // --- REJECT ---
      // A slot frees up when the OLDEST in-window request ages out.
      const oldest = timestamps[0];
      const retryAfterMs = Math.max(0, oldest + windowMs - now);
      const retryAfterSec = Math.max(1, Math.ceil(retryAfterMs / 1000));
      const resetEpochSec = Math.ceil((oldest + windowMs) / 1000);

      res.setHeader('X-RateLimit-Limit', maxRequests);
      res.setHeader('X-RateLimit-Remaining', 0);
      res.setHeader('X-RateLimit-Reset', resetEpochSec);
      res.setHeader('Retry-After', retryAfterSec);

      res.status(429).json({
        error: 'Rate limit exceeded',
        retryAfter: retryAfterSec,
      });
      return; // Do NOT call next().
    }

    // --- ALLOW ---
    timestamps.push(now);

    const remaining = maxRequests - timestamps.length;
    // Window resets (relative to now) one full windowMs after the oldest
    // currently-tracked request — when a slot next frees up.
    const resetEpochSec = Math.ceil((timestamps[0] + windowMs) / 1000);

    res.setHeader('X-RateLimit-Limit', maxRequests);
    res.setHeader('X-RateLimit-Remaining', remaining);
    res.setHeader('X-RateLimit-Reset', resetEpochSec);

    next();
  };

  // --- Periodic memory reclamation ---
  // Without this, the Map grows one entry per unique IP forever. The sweep
  // evicts expired timestamps and deletes any key whose array is then empty
  // (an IP with no requests within the last windowMs).
  const cleanupTimer = setInterval(() => {
    const windowStart = Date.now() - windowMs;
    for (const [key, timestamps] of hits) {
      evictExpired(timestamps, windowStart);
      if (timestamps.length === 0) {
        hits.delete(key);
      }
    }
  }, cleanupIntervalMs);

  // Don't let the timer keep the process alive. Guarded for runtimes where
  // setInterval returns a plain number rather than a Node Timeout.
  if (typeof cleanupTimer.unref === 'function') {
    cleanupTimer.unref();
  }

