   * Stop the cleanup timer and release state. Call on graceful shutdown / test
   * teardown so the interval cannot keep the event loop (and process) alive.
   */
  middleware.close = function close() {
    clearInterval(cleanupTimer);
    hits.clear();
  };

  return middleware;
}

