 * @typedef {Object} RateLimiterOptions
 * @property {number} [windowMs=60000]   Sliding window size in milliseconds.
 * @property {number} [maxRequests=100]  Max requests allowed per window.
 */

/**
 * @typedef {Object} RateLimiter
 * @property {import('express').RequestHandler} middleware
 * @property {() => void} close  Clears the cleanup interval (call on shutdown).
 */

/**
 * Creates a sliding-window rate limiter.
 *
 * @param   {RateLimiterOptions} [options]
 * @returns {RateLimiter}
 */
function createRateLimiter(options = {}) {
  const windowMs    = options.windowMs    ?? 60_000;  // default: 1 minute
  const maxRequests = options.maxRequests ?? 100;

  if (!Number.isFinite(windowMs) || windowMs <= 0) {
    throw new RangeError('windowMs must be a positive finite number');
  }
  if (!Number.isInteger(maxRequests) || maxRequests <= 0) {
    throw new RangeError('maxRequests must be a positive integer');
  }

  // ─── store ─────────────────────────────────────────────────────────────────
  // Map<ip: string, timestamps: number[]>
  // Arrays are always maintained in ascending order (oldest first) because
  // we only ever append to the tail and prune from the head.
  const store = new Map();

  // ─── periodic cleanup ──────────────────────────────────────────────────────
  // IPs that stop sending requests would otherwise linger in memory forever.
  // Every 60 s we drop any entry whose *newest* timestamp is already outside
  // the window — it can no longer affect any future rate-limit decision.
