  // exiting naturally.  Call close() for an explicit, synchronous teardown
  // (e.g. in tests or graceful-shutdown handlers).
  const cleanupTimer = setInterval(() => {
    const cutoff = Date.now() - windowMs;
    for (const [ip, timestamps] of store) {
      // Array is ascending → last element is most recent.
      if (timestamps.length === 0 || timestamps[timestamps.length - 1] < cutoff) {
        store.delete(ip);
      }
    }
  }, 60_000);

  if (typeof cleanupTimer.unref === 'function') {
    cleanupTimer.unref();   // belt-and-suspenders: won't block process exit
  }

  // ─── middleware ────────────────────────────────────────────────────────────
  function middleware(req, res, next) {
    const now         = Date.now();
    const windowStart = now - windowMs;

    // req.ip honours trust-proxy; socket fallback covers plain http.Server use.
