    //    Timestamps are ascending, so everything before pruneIdx is stale.
    let pruneIdx = 0;
    while (pruneIdx < timestamps.length && timestamps[pruneIdx] < windowStart) {
      pruneIdx++;
    }
    if (pruneIdx > 0) {
      timestamps = timestamps.slice(pruneIdx);   // evict the stale head
